// src/App.js
import React from "react";
import { Routes, Route, Navigate } from "react-router-dom";
import Login from "./pages/Login";
import Register from "./pages/Register";
import Booking from "./pages/Booking";
import RideTrack from "./pages/RideTrack";
import History from "./pages/History";
import Profile from "./pages/Profile";
import AdminDashboard from "./pages/AdminDashboard";
import RiderDashboard from "./pages/dashboards/RiderDashboard";
import UserDashboard from "./pages/dashboards/UserDashboard"; // ✅ create if missing
import DocumentUpload from "./pages/DocumentUpload"; // ✅ added upload page
import Navbar from "./components/Navbar";
import { useAuth } from "./contexts/AuthContext";

export default function App() {
  const { user } = useAuth();
  const role = localStorage.getItem("role");

  return (
    <>
      <Navbar />
      <main style={{ padding: 20 }}>
        <Routes>
          {/* Default redirect based on login */}
          <Route
            path="/"
            element={
              user ? (
                role === "rider" ? (
                  <Navigate to="/rider-dashboard" />
                ) : (
                  <Navigate to="/user-dashboard" />
                )
              ) : (
                <Navigate to="/login" />
              )
            }
          />

          {/* Auth routes */}
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />

          {/* Rider routes */}
          <Route
            path="/rider-dashboard"
            element={
              user && role === "rider" ? (
                <RiderDashboard />
              ) : (
                <Navigate to="/login" />
              )
            }
          />
          <Route
            path="/upload-docs"
            element={
              user && role === "rider" ? (
                <DocumentUpload />
              ) : (
                <Navigate to="/login" />
              )
            }
          />

          {/* User routes */}
          <Route
            path="/user-dashboard"
            element={
              user && role === "user" ? (
                <UserDashboard />
              ) : (
                <Navigate to="/login" />
              )
            }
          />

          {/* Common routes */}
          <Route
            path="/booking"
            element={user ? <Booking /> : <Navigate to="/login" />}
          />
          <Route
            path="/ride/:id"
            element={user ? <RideTrack /> : <Navigate to="/login" />}
          />
          <Route
            path="/history"
            element={user ? <History /> : <Navigate to="/login" />}
          />
          <Route
            path="/profile"
            element={user ? <Profile /> : <Navigate to="/login" />}
          />

          {/* Admin */}
          <Route
            path="/admin"
            element={
              user && role === "admin" ? (
                <AdminDashboard />
              ) : (
                <Navigate to="/login" />
              )
            }
          />

          {/* Fallback */}
          <Route path="*" element={<div>404 Not Found</div>} />
        </Routes>
      </main>
    </>
  );
}
